"use strict";(globalThis.webpackChunkstaticdocs_starter=globalThis.webpackChunkstaticdocs_starter||[]).push([[4136],{73120(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"2025-09-18-release","metadata":{"permalink":"/zh-Hans/blog/2025-09-18-release","source":"@site/blog/2025-09-18-release.md","title":"v2025.09.18 Release","description":"Optimizations","date":"2025-09-18T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"}],"readingTime":0.17,"hasTruncateMarker":false,"authors":[{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"2025-09-18-release","title":"v2025.09.18 Release","authors":{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png"},"tags":["release"]},"unlisted":false,"nextItem":{"title":"v2025.03.31 Release","permalink":"/zh-Hans/blog/2025-03-31-release"}},"content":"## Optimizations\\n\\nThis release brings Kotlin default arguments optimization in Constant Propagation.\\n\\n## Other improvements\\n\\n- More adoptions of the new unordered container type.\\n- Reducing Redex memory usage (via inliner\u2019s new max_reduced_size option).\\n- JarLoader improvements for fuzzing."},{"id":"2025-03-31-release","metadata":{"permalink":"/zh-Hans/blog/2025-03-31-release","source":"@site/blog/2025-03-31-release.md","title":"v2025.03.31 Release","description":"Optimizations","date":"2025-03-31T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"}],"readingTime":0.39,"hasTruncateMarker":false,"authors":[{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"2025-03-31-release","title":"v2025.03.31 Release","authors":{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png"},"tags":["release"]},"unlisted":false,"prevItem":{"title":"v2025.09.18 Release","permalink":"/zh-Hans/blog/2025-09-18-release"},"nextItem":{"title":"v2024.10.31 Release","permalink":"/zh-Hans/blog/2024-10-31-release"}},"content":"## Optimizations\\n\\nThis release brings enhancements to existing optimizations:\\n\\n- `BranchPrefixHoisting` runs more often, hoisting more instructions.\\n- Improvements to inlining, inlining almost 1% more callsites while reducing code-size overall.\\n- Improvements to source blocks for merged classes.\\n- New pass `InsertDebugInfoPass` to insert artificial debug info for incoming code that is missing line numbers.\\n- Improvements to constant propagation analyzers to evaluate package names.\\n\\n## Other improvements\\n\\n- Improvements to `.pro` parsing logic and dex loading logic (not expected to change application perf)."},{"id":"2024-10-31-release","metadata":{"permalink":"/zh-Hans/blog/2024-10-31-release","source":"@site/blog/2024-10-31-release.md","title":"v2024.10.31 Release","description":"Optimizations","date":"2024-10-31T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"}],"readingTime":0.39,"hasTruncateMarker":false,"authors":[{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"2024-10-31-release","title":"v2024.10.31 Release","authors":{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png"},"tags":["release"]},"unlisted":false,"prevItem":{"title":"v2025.03.31 Release","permalink":"/zh-Hans/blog/2025-03-31-release"},"nextItem":{"title":"v2024.08.31 Release","permalink":"/zh-Hans/blog/2024-08-31-release"}},"content":"## Optimizations\\n\\nThis is a relatively small incremental release bringing two new optimizations:\\n\\n- A new resource inlining pass, inlining universally constant resources values directly in the code, eliminating expensive resource lookups. This first implementation only considers colors, ints and bools, but does not yet consider strings.\\n- Eliminating unused arguments in true virtual methods. This reduces method invocation overhead for virtual methods.\\n\\n## Other improvements\\n\\n- Support for `-assumevalues` in ProGuard specifications, as supported by R8. This unlocks additional optimizations in Redex."},{"id":"2024-08-31-release","metadata":{"permalink":"/zh-Hans/blog/2024-08-31-release","source":"@site/blog/2024-08-31-release.md","title":"v2024.08.31 Release","description":"Optimizations","date":"2024-08-31T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"}],"readingTime":0.63,"hasTruncateMarker":false,"authors":[{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"2024-08-31-release","title":"v2024.08.31 Release","authors":{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png"},"tags":["release"]},"unlisted":false,"prevItem":{"title":"v2024.10.31 Release","permalink":"/zh-Hans/blog/2024-10-31-release"},"nextItem":{"title":"v2024.05.31 Release","permalink":"/zh-Hans/blog/2024-05-31-release"}},"content":"## Optimizations\\n\\nThis release bundles a few improved optimizations that improve code size and performance:\\n\\n- Relax init optimization that inlines the constructor calls at object instantiation site. As a result, we can also remove the constructor method from the class.\\n- By reordering classes in `InterdexPass`, we made dexes more dense after Halfnosis pass and empty dexes will be left behind and can be removed by the newly introduced `DexRemovalPass`.\\n\\n## Better Engineering & Reliability Improvements\\n\\n- Improved dead resource elimination, to bring parity between `.apk` and `.aab` builds for removed resources.\\n- Classes using the `ServiceLoader` Java APIs will now be kept by Redex; keep rules are no longer necessary.\\n- Class renaming improvements to better identify class names used by layout files and string references.\\n- Improved annotation handling in `SingleImplPass`."},{"id":"2024-05-31-release","metadata":{"permalink":"/zh-Hans/blog/2024-05-31-release","source":"@site/blog/2024-05-31-release.md","title":"v2024.05.31 Release","description":"Optimizations","date":"2024-05-31T00:00:00.000Z","tags":[{"inline":true,"label":"release","permalink":"/zh-Hans/blog/tags/release"}],"readingTime":0.62,"hasTruncateMarker":false,"authors":[{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"2024-05-31-release","title":"v2024.05.31 Release","authors":{"name":"Redex Team","title":"Redex Team","url":"https://fbredex.com","image_url":"https://fbredex.com/img/favicon.png","imageURL":"https://fbredex.com/img/favicon.png"},"tags":["release"]},"unlisted":false,"prevItem":{"title":"v2024.08.31 Release","permalink":"/zh-Hans/blog/2024-08-31-release"},"nextItem":{"title":"Office Hours","permalink":"/zh-Hans/blog/office-hours"}},"content":"## Optimizations\\n\\nThis release bundles a few improved optimizations that improve code size and performance:\\n\\n- Improvements to object escape analysis and associated transformations (support for check-casts, returning parameters, true virtual and super invocations, comparing objects with null, and a whole new global cost function), resulting in fewer object allocations and more inlining.\\n- Streamlined treatment of system annotations (a conceptual cleanup effort that lead to a size reduction).\\n- Value numbering for branch conditions eliminating branches in code.\\n\\n## Build Speed / Reliability / Better Engineering\\n\\n- Improved precision of analysis for class references from layouts and XML attributes, preventing Redex from removing referenced classes.\\n- First steps towards addressing an ancient design bug in Redex causing improper handling of the `package-private` access modifier.\\n- Performance improvements to Redex infrastructure."},{"id":"office-hours","metadata":{"permalink":"/zh-Hans/blog/office-hours","source":"@site/blog/2022-10-26-office-hours.md","title":"Office Hours","description":"!!! Redex Public Office Hour Coming on Wed. 10/26/2022 @2PM PST !!!","date":"2022-10-26T00:00:00.000Z","tags":[{"inline":true,"label":"redex","permalink":"/zh-Hans/blog/tags/redex"}],"readingTime":0.43,"hasTruncateMarker":false,"authors":[{"name":"Nikolai Tillmann","title":"Redex Team","url":"https://github.com//NTillmann","image_url":"https://github.com/NTillmann.png","imageURL":"https://github.com/NTillmann.png","socials":{},"key":null,"page":null}],"frontMatter":{"slug":"office-hours","title":"Office Hours","authors":{"name":"Nikolai Tillmann","title":"Redex Team","url":"https://github.com//NTillmann","image_url":"https://github.com/NTillmann.png","imageURL":"https://github.com/NTillmann.png"},"tags":["redex"]},"unlisted":false,"prevItem":{"title":"v2024.05.31 Release","permalink":"/zh-Hans/blog/2024-05-31-release"}},"content":"!!! Redex Public Office Hour Coming on Wed. 10/26/2022 @2PM PST !!!\\n\\n[Zoom Meeting id: 921 3454 5091; passcode: 177943](https://fb.zoom.us/j/92134545091?pwd=NDRZSEhQSXBpeEVxTUF4Y3NMYjU3dz09)\\n\\nPlease dial in to chat! We would love to learn how do you use Redex, what challenges are\\nyou facing, and how can we better help. We would like keep the 1st office hour to be more\\nhigh level. If you have very specific questions, like how to build Redex, Github issue is still\\nthe best way to resolve it."}]}}')}}]);